    @Transactional
    public CatalogSeedResult seedCoreCatalog() {
        Map<String, ServiceCategory> categories = seedCategories();
        Map<String, ServiceModule> modules = seedModules(categories);
        seedDependencies(modules);
        seedPackageTemplates(modules);
        seedTemplateDefinitions();
        seedRules(modules);
        seedAiCapabilityConfigs();
        return new CatalogSeedResult(categories.size(), modules.size());
    }

    private Map<String, ServiceCategory> seedCategories() {
        List<CategorySeed> seeds = List.of(
                new CategorySeed("validation", "Validation", "Product diagnosis, requirements, readiness, and productization scope.", 1),
                new CategorySeed("code-rewrite-refactor", "Code Modernization", "Refactor, rewrite, and clean up product code into maintainable systems.", 2),
                new CategorySeed("security", "Security Hardening", "Auth, API, dependency, privacy, payment, and evidence-backed remediation.", 3),
                new CategorySeed("cloud-devops", "Cloud / DevOps", "Deployment, CI/CD, staging, rollback, monitoring, and production environment control.", 4),
                new CategorySeed("database", "Database / Data", "Schema, migrations, query performance, backups, integrity, and tenant isolation.", 5),
                new CategorySeed("scaling", "Scaling / Performance", "Load, cost, resilience, caching, queues, and architecture readiness for growth.", 6),
                new CategorySeed("launch-gtm-readiness", "Launch Readiness", "Onboarding, analytics, payments, admin tools, beta, docs, and go-live controls.", 7),
                new CategorySeed("operations-support", "Operations / Support", "Maintenance, monitoring, incidents, releases, patching, and ongoing product health.", 8)
        );
        Map<String, ServiceCategory> categories = new LinkedHashMap<>();
        for (CategorySeed seed : seeds) {
            ServiceCategory category = categoryRepository.findBySlug(seed.slug()).orElseGet(ServiceCategory::new);
            category.setSlug(seed.slug());
            category.setName(seed.name());
            category.setDescription(seed.description());
            category.setSortOrder(seed.sortOrder());
            category.setActive(true);
            categories.put(seed.slug(), categoryRepository.save(category));
        }
        return categories;
    }

