    private void seedDependencies(Map<String, ServiceModule> modules) {
        List<DependencySeed> seeds = List.of(
                dependency("code.backend_rewrite", "db.schema_redesign", "Backend rewrites often change schema, migrations, and data ownership.", ServiceDependency.DependencyType.HARD, ServiceDependency.DependencySeverity.BLOCKER),
                dependency("code.frontend_rewrite", "validation.requirements", "Frontend rewrite should be grounded in accepted user workflows and role-specific requirements.", ServiceDependency.DependencyType.HARD, ServiceDependency.DependencySeverity.WARNING),
                dependency("code.no_code_migration", "db.migration_plan", "No-code migration needs a data and workflow migration plan before execution.", ServiceDependency.DependencyType.HARD, ServiceDependency.DependencySeverity.BLOCKER),
                dependency("code.auth_rebuild", "security.rbac_review", "Auth rebuild needs role and ownership rules to avoid insecure access paths.", ServiceDependency.DependencyType.HARD, ServiceDependency.DependencySeverity.BLOCKER),
                dependency("code.multitenant_refactor", "db.tenant_isolation", "Multi-tenant code changes must include database tenant-isolation verification.", ServiceDependency.DependencyType.HARD, ServiceDependency.DependencySeverity.BLOCKER),
                dependency("security.payment_review", "launch.payment_setup", "Payment security findings should flow into payment implementation and verification.", ServiceDependency.DependencyType.PARALLEL, ServiceDependency.DependencySeverity.WARNING),
                dependency("cloud.deployment_setup", "cloud.cicd_setup", "Production deployment needs repeatable CI/CD checks.", ServiceDependency.DependencyType.HARD, ServiceDependency.DependencySeverity.BLOCKER),
                dependency("cloud.deployment_setup", "cloud.monitoring_setup", "Production deployment needs monitoring before support handoff.", ServiceDependency.DependencyType.HARD, ServiceDependency.DependencySeverity.BLOCKER),
                dependency("cloud.deployment_setup", "cloud.backup_restore", "Live systems need backup and restore readiness.", ServiceDependency.DependencyType.HARD, ServiceDependency.DependencySeverity.WARNING),
                dependency("cloud.rollback_setup", "cloud.cicd_setup", "Rollback work depends on a known release pipeline and deployment path.", ServiceDependency.DependencyType.HARD, ServiceDependency.DependencySeverity.WARNING),
                dependency("db.migration_execution", "db.migration_plan", "Migration execution requires an approved migration plan.", ServiceDependency.DependencyType.HARD, ServiceDependency.DependencySeverity.BLOCKER),
                dependency("scale.load_testing", "cloud.staging_setup", "Load testing needs a staging or test environment that can absorb synthetic traffic.", ServiceDependency.DependencyType.ACCESS, ServiceDependency.DependencySeverity.WARNING),
                dependency("scale.database_optimization", "db.query_optimization", "Database optimization should use query-level evidence and index plans.", ServiceDependency.DependencyType.SOFT, ServiceDependency.DependencySeverity.RECOMMENDED),
                dependency("launch.go_live_checklist", "cloud.rollback_setup", "Go-live needs a rollback plan before owner approval.", ServiceDependency.DependencyType.HARD, ServiceDependency.DependencySeverity.BLOCKER),
                dependency("launch.go_live_checklist", "launch.support_readiness", "Go-live needs support ownership and escalation paths.", ServiceDependency.DependencyType.HARD, ServiceDependency.DependencySeverity.WARNING),
                dependency("support.handoff", "cloud.deployment_handoff", "Support handoff needs deployment handoff details for safe operations.", ServiceDependency.DependencyType.HARD, ServiceDependency.DependencySeverity.WARNING),
                dependency("support.security_patching", "security.dependency_review", "Patching should be driven by dependency review evidence.", ServiceDependency.DependencyType.SOFT, ServiceDependency.DependencySeverity.RECOMMENDED)
        );
        for (DependencySeed seed : seeds) {
            ServiceModule source = modules.get(seed.sourceCode());
            ServiceModule target = modules.get(seed.targetCode());
            if (source == null || target == null) {
                continue;
            }
            ServiceDependency dependency = dependencyRepository.findBySourceModuleId(source.getId()).stream()
                    .filter(existing -> existing.getDependsOnModule().getId().equals(target.getId()))
                    .findFirst()
                    .orElseGet(ServiceDependency::new);
            dependency.setSourceModule(source);
            dependency.setDependsOnModule(target);
            dependency.setReason(seed.reason());
            dependency.setMessage(seed.reason());
            dependency.setDependencyType(seed.type());
            dependency.setSeverity(seed.severity());
            dependency.setRequired(seed.severity() == ServiceDependency.DependencySeverity.BLOCKER);
            dependency.setRuleMetadata("{\"source\":\"catalog-core-seed\"}");
            dependencyRepository.save(dependency);
        }
    }

