    private void seedRules(Map<String, ServiceModule> modules) {
        List<RuleSeed> seeds = List.of(
                rule("goal-payments-security", CatalogRule.RuleType.GOAL_KEYWORD, "payment", null, "security.payment_review", ServiceDependency.DependencySeverity.WARNING, "Payment products should include payment security and entitlement review."),
                rule("goal-enterprise-evidence", CatalogRule.RuleType.GOAL_KEYWORD, "enterprise", null, "security.evidence_review", ServiceDependency.DependencySeverity.RECOMMENDED, "Enterprise paths usually need evidence review before buyer-facing claims."),
                rule("goal-launch-support", CatalogRule.RuleType.GOAL_KEYWORD, "launch", null, "launch.go_live_checklist", ServiceDependency.DependencySeverity.WARNING, "Launch goals should include a go-live checklist."),
                rule("goal-scale-load", CatalogRule.RuleType.GOAL_KEYWORD, "scale", null, "scale.load_testing", ServiceDependency.DependencySeverity.RECOMMENDED, "Scaling goals should include repeatable load tests."),
                rule("selected-auth-rbac", CatalogRule.RuleType.SERVICE_SELECTED, "code.auth_rebuild", "code.auth_rebuild", "security.rbac_review", ServiceDependency.DependencySeverity.BLOCKER, "Auth rebuild must include role and ownership verification."),
                rule("selected-deploy-handoff", CatalogRule.RuleType.SERVICE_SELECTED, "cloud.deployment_setup", "cloud.deployment_setup", "cloud.deployment_handoff", ServiceDependency.DependencySeverity.RECOMMENDED, "Deployment setup should finish with handoff documentation."),
                rule("selected-support-health", CatalogRule.RuleType.SERVICE_SELECTED, "support.basic_maintenance", "support.basic_maintenance", "support.monthly_health_review", ServiceDependency.DependencySeverity.RECOMMENDED, "Ongoing maintenance should include a recurring owner health review.")
        );
        int order = 1;
        for (RuleSeed seed : seeds) {
            ServiceModule recommended = modules.get(seed.recommendedCode());
            if (recommended == null) {
                continue;
            }
            CatalogRule rule = ruleRepository.findBySlug(seed.slug()).orElseGet(CatalogRule::new);
            rule.setSlug(seed.slug());
            rule.setRuleType(seed.type());
            rule.setTriggerKey(seed.triggerKey());
            rule.setSourceModule(seed.sourceCode() == null ? null : modules.get(seed.sourceCode()));
            rule.setRecommendedModule(recommended);
            rule.setSeverity(seed.severity());
            rule.setMessage(seed.message());
            rule.setRuleMetadata("{\"source\":\"catalog-core-seed\",\"aiReady\":true,\"aiExecuted\":false}");
            rule.setHumanReviewRequired(true);
            rule.setActive(true);
            rule.setSortOrder(order++);
            ruleRepository.save(rule);
        }
    }

    private void seedAiCapabilityConfigs() {
        List<AIConfigSeed> seeds = List.of(
                ai("product-diagnosis-assist", "Product Diagnosis Assist", "DIAGNOSIS", "Suggest diagnosis findings from owner-provided evidence and platform records."),
                ai("service-plan-assist", "Service Plan Assist", "PACKAGE_COMPOSITION", "Suggest service sequences using catalog IDs, dependencies, templates, and evidence state."),
                ai("team-match-explain", "Team Match Explanation", "TEAM_MATCHING", "Explain why a verified team or solo expert fits a service plan."),
                ai("milestone-review-assist", "Milestone Review Assist", "MILESTONE_REVIEW", "Summarize evidence and risks for human milestone approval."),
                ai("support-triage-assist", "Support Triage Assist", "SUPPORT_TRIAGE", "Suggest support priority, owner, and next response from workspace evidence."),
                ai("admin-governance-audit", "Admin Governance Audit", "ADMIN_GOVERNANCE", "Find catalog drift, missing evidence requirements, and unsupported claims.")
        );
        int order = 1;
        for (AIConfigSeed seed : seeds) {
            AICapabilityConfig config = aiCapabilityConfigRepository.findBySlug(seed.slug()).orElseGet(AICapabilityConfig::new);
            config.setSlug(seed.slug());
            config.setName(seed.name());
            config.setCapabilityType(seed.type());
            config.setDescription(seed.description());
            config.setInputContract("{\"allowedInputs\":[\"catalogIds\",\"productId\",\"workspaceId\",\"evidenceIds\",\"userRole\"],\"requiresTenantScope\":true}");
            config.setOutputContract("{\"recommendations\":\"array\",\"rationale\":\"string\",\"citations\":\"array\",\"confidence\":\"number\",\"requiresHumanReview\":true}");
            config.setAllowedSources("ProdUS catalog, product records, package modules, workspace milestones, evidence attachments, support records.");
            config.setForbiddenClaims("No legal, compliance, security certification, production guarantee, or uncited claim may be produced.");
            config.setHumanReviewRequired(true);
            config.setEnabled(false);
            config.setSortOrder(order++);
            aiCapabilityConfigRepository.save(config);
        }
    }

